mapper.select:
SELECT * FROM( SELECT TOP 500 itfl.Seq , Row_Number() OVER (order by CONVERT(NUMERIC(6,2), ISNULL(itfl.Version,TCS.Version)) ASC, itfl.LastUpdated ASC, itfl.FltpCode ASC, itfl.FileRealName ASC) AS RNUM ,0 as CHK ,itfl.DocumentID ,itfl.DocCategory ,itfl.LinkType ,itfl.FileName ,itfl.FltpCode ,itfl.FileFormat ,itfl.FileRealName ,itfl.FileSize ,itfl.FileMgt ,itfl.RegMemberID ,itfl.RefFileID ,CONVERT(CHAR(10),CONVERT(datetime,itfl.CreationTime),21) as CreationTime ,CONVERT(CHAR(10),CONVERT(datetime,itfl.LastUpdated),21) as LastUpdated ,itfl.LastUser ,ISNULL(itfl.Version,TCS.Version) AS Version ,itfl.DownCNT ,ISNULL(mbr.Name,'') + Case When ISNULL(mbr.NameEN,'') != '' Then '(' + ISNULL(mbr.NameEN,'') + ')' Else '' End AS WriteUserNM
,fltp.FilePath+itfl.FileName as SysFile ,fltp.FilePath+itfl.FileRealName as OrigFile ,fltp.FilePath ,itfl.FilePath as ExtFileURL
,td.Name as FltpName
,TIC.FileOption AS fileOption ,ti2.ItemTypeCode As ItemTypeCode ,( select t2.name from XBOLTADM.TB_MEMBER t1 WITH (NOLOCK) left outer join XBOLTADM.TB_TEAM_TXT t2 WITH (NOLOCK) on t1.teamId = t2.teamId where t1.memberId = itfl.RegMemberID and t2.LanguageID = #{languageID} ) as TeamName
,ISNULL(TIPT.Path, '') + '/' + +ISNULL(TIA.PlainText,'') AS Path
,TIA1.PlainText +'/'+TIA2.PlainText AS Path
,TIA3.PlainText +'/'+TIA4.PlainText AS Path
, XBOLTADM.fn_getMyAbsPathForProject(itfl.ProjectID, #{languageID}) AS Path
,ISNULL(TIPT2.Path, '') + '/' +ISNULL(TIA.PlainText,'') AS Path
, Case fltp.DocCategory When 'SR' Then SR.SRCode Else SCR.SCRCode End AS DocCode
,ti2.ClassCode ,TL.LanguageCode ,CASE WHEN itfl.Blocked != 0 then 'Y' ELSE '-' END Blocked ,ISNULL(TDF.Name,'') AS FileStatus ,ISNULL(TCS.Version, '-') AS CSVersion FROM XBOLTADM.TB_FILE itfl WITH (NOLOCK) LEFT OUTER JOIN XBOLTADM.TB_MEMBER mbr WITH (NOLOCK) ON itfl.RegMemberID = mbr.MemberID LEFT OUTER JOIN XBOLTADM.TB_FLTP fltp WITH (NOLOCK) ON itfl.FltpCode = fltp.FltpCode LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY td WITH (NOLOCK) ON itfl.FltpCode = td.TypeCode AND td.languageID = #{languageID} Left Outer Join XBOLTADM.TB_ITEM ti2 WITH (NOLOCK) On ti2.ItemID = itfl.DocumentID And ti2.Deleted = 0 Left Outer Join XBOLTADM.TB_PROJECT TP WITH (NOLOCK) ON TP.ProjectID = itfl.ProjectID Left Outer Join XBOLTADM.TB_LANGUAGE TL WITH (NOLOCK) On TL.LanguageID = itfl.LanguageID Left Outer Join XBOLTADM.TB_CHANGE_SET TCS WITH (NOLOCK) On TCS.ChangeSetID = itfl.ChangeSetID
Left outer join XBOLTAPP.ESM_SR_MST SR WITH (NOLOCK) on itfl.DocumentID = SR.SRID and itfl.DocCategory = 'SR' Left outer join XBOLTADM.TB_ITEM_ATTR TIA1 WITH (NOLOCK) on SR.SRArea1 = TIA1.ItemID and TIA1.LanguageID = #{languageID} and TIA1.AttrTypeCode = 'AT00001' Left outer join XBOLTADM.TB_ITEM_ATTR TIA2 WITH (NOLOCK) on SR.SRArea2 = TIA2.ItemID and TIA2.LanguageID = #{languageID} and TIA2.AttrTypeCode = 'AT00001'
Left outer join XBOLTAPP.ESM_SCR_MST SCR WITH (NOLOCK) on itfl.DocumentID = SCR.SCRID and itfl.DocCategory = 'SCR' Left outer join XBOLTADM.TB_ITEM_ATTR TIA3 WITH (NOLOCK) on SCR.SCRArea1 = TIA3.ItemID and TIA3.LanguageID = #{languageID} and TIA3.AttrTypeCode = 'AT00001' Left outer join XBOLTADM.TB_ITEM_ATTR TIA4 WITH (NOLOCK) on SCR.SCRArea2 = TIA4.ItemID and TIA4.LanguageID = #{languageID} and TIA4.AttrTypeCode = 'AT00001'
Left Outer join XBOLTADM.TW_ITEM_PATH_TXT TIPT WITH (NOLOCK) ON TIPT.ItemID = itfl.DocumentID And TIPT.LanguageID = #{languageID} Left Outer join XBOLTADM.TW_ITEM_PATH_TXT TIPT2 WITH (NOLOCK) ON TIPT2.ItemID = itfl.ItemID And TIPT2.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA WITH (NOLOCK) ON TIA.ItemID = itfl.DocumentID And TIA.AttrTypeCode = 'AT00001' And TIA.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TDF WITH (NOLOCK) ON itfl.Blocked = TDF.TypeCode AND TDF.languageID = #{languageID} And TDF.Category = 'FILESTS' Left OUter Join XBOLTADM.TB_ITEM_CLASS TIC WITH (NOLOCK) ON TIC.ItemClassCode = ti2.ClassCode
And itfl.Blocked != 2
AND itfl.Blocked = 0
AND itfl.languageID = #{languageID}
And itfl.DocCategory IN('SR','SCR')
And itfl.DocCategory = #{DocCategory}
And ti2.ItemTypeCode = #{itemTypeCode}
And ti2.ClassCode = #{classCode}
And (itfl.RegMemberID = #{sessionUserId} or itfl.lastUser = #{sessionUserId} )
AND ti2.Deleted = #{deleted}
AND itfl.DocumentID = #{DocumentID}
AND itfl.fltpCode = #{fltpCode}
AND TP.RefPjtID = #{parentID}
AND itfl.ProjectID = #{projectID}
AND itfl.ChangeSetID = #{changeSetID}
AND ti2.OwnerTeamID = #{ownerTeamID}
AND TP.RefPjtID = #{refPjtID}
OR (itfl.DocumentID IN(${rltdItemId}) ANd fltp.FltpCode IN (Select FltpCode From XBOLTADM.TB_FLTP_ALLOC WITH (NOLOCK) Where ItemClassCode =(Select ClassCode From XBOLTADM.TB_ITEM WITH (NOLOCK) Where ItemID = #{s_itemID}) AND LinkType = '02') AND itfl.Blocked = 0
)
OR itfl.DocumentID IN('')
AND itfl.fileRealName like N'%'+#{searchValue}+'%'
AND itfl.Description like N'%'+#{searchValue}+'%'
And CONVERT(varchar(10), itfl.LastUpdated, 120) BETWEEN #{updatedStartDT} AND #{updatedEndDT}
And mbr.Name like N'%'+#{regMemberName}+'%'
And fltp.IsPublic = 1
order by ISNULL(itfl.Version,TCS.Version) DESC, itfl.LastUpdated DESC, itfl.FltpCode ASC, itfl.FileRealName ASC ) TC
And TC.Path like N'%'+#{path}+'%'
order by TC.RNUM DESC

mapper.insert:
	INSERT INTO XBOLTADM.TB_FILE (
		
			DocumentID,
		
		DocCategory	
		,ProjectID
		,LinkType	
		,FileName
		
			,FilePath
		
		
			,FltpCode
		
		
			,ItemID
		
		
			,ChangeSetID
		
		
			,RefFileID
		
		,FileRealName
		,FileSize
		,FileMgt
		,FileFormat
		,RegMemberID
		,CreationTime
		,LastUpdated
		,LastUser
		,DownCNT
		,LanguageID
		,Blocked
		
			,Description
		
		
			,SpeCode
		
		
			,RefDocumentID
		
	)
	VALUES (
		
			#{DocumentID}, 
		
		 
		#{DocCategory} 
		, #{projectID}
		, #{LinkType}
		, #{FileName}
		
			, #{FilePath}
		
		
			, #{FltpCode}
		
		
			,#{ItemID}
		
		
			, #{ChangeSetID}
		
		
			, #{RefFileID}
		
		, #{FileRealName}
		, #{FileSize}
		, #{FileMgt}
		, #{FileFormat}
		, #{userId}
		, getDate()
		, getDate()
		, #{userId}
		, 0
		, #{LanguageID}
 		
		
			,1
						
 		,0
 					 			 	
		
			,#{Description}
		
		
			,#{speCode}
		
		
			,#{refDocumentID}
		
	)

mapper.update:
UPDATE XBOLTADM.TB_FILE SET
	FltpCode = #{FltpCode}
	,FileName = #{FileName}
	,FileRealName = #{FileRealName}
	,FileSize = #{FileSize}
	,ProjectID = #{projectID}
	,ChangeSetID = #{ChangeSetID}
	,Blocked = #{Blocked}
	,FileFormat = #{FileFormat}
	
		
			,FilePath = ''
		
		
			,FilePath = #{FilePath}
		
 		,FilePath = NULL
 		
	, Description = #{Description}
	, LastUpdated = getDate()
	, LastUser = #{sessionUserId}
	, LanguageID = #{LanguageID}
WHERE Seq = #{Seq}

UPDATE XBOLTADM.TB_FILE SET
	DownCNT = ISNULL(DownCNT,0)+1
WHERE Seq = #{Seq}

mapper.select:
SELECT  ClassCode as itemClassCode
FROM XBOLTADM.TB_ITEM
WHERE ItemID = #{itemID}

SELECT TOP 1000 itfl.FileSize as size , #{baseUrl}+SubString(fltp.FilePath,30,len(fltp.FilePath))+itfl.FileRealName as filePath ,itfl.FileRealName as fileName ,itfl.Seq as id FROM XBOLTADM.TB_FILE itfl LEFT OUTER JOIN XBOLTADM.TB_MEMBER mbr ON itfl.RegMemberID = mbr.MemberID LEFT OUTER JOIN XBOLTADM.TB_FLTP fltp ON itfl.FltpCode = fltp.FltpCode LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY td ON itfl.FltpCode = td.TypeCode LEFT OUTER JOIN XBOLTADM.TB_FLTP_ALLOC fltpalc ON itfl.FltpCode = fltpalc.FltpCode WHERE 1=1 AND td.LanguageID = #{languageID}
AND itfl.DocumentID = #{itemId}
AND fltpalc.ItemClassCode = #{itemClassCode}
AND fltp.fltpCode = #{fltpCode}
AND itfl.fileRealName like N'%'+#{searchValue}+'%'
order by itfl.CreationTime desc

		SELECT 	Count(*)
  		FROM XBOLTADM.TB_FILE 
  		WHERE DocCategory = #{docCategory} 
  			
  			 AND speCode = #{speCode}
  			
  			
  			 AND ChangeSetID = #{changeSetID}
  			
  			
  			 AND DocumentID = #{documentID}

WITH ItemMaster(MyItemID) AS ( SELECT ITM.ItemID AS MyItemID FROM XBOLTADM.TB_ITEM ITM WHERE ITM.ParentID = #{strItemID} AND ITM.CategoryCode = 'ST2' AND ITM.Deleted != '1' AND (Select Deleted From XBOLTADM.TB_ITEM Where ItemID = ITM.ToItemID ) != '1' UNION ALL SELECT ITM_L.ItemID AS MyItemID FROM XBOLTADM.TB_ITEM ITM_L, ItemMaster LCTE, XBOLTADM.TB_ITEM ITM WHERE ITM_L.Deleted != '1' AND ITM_L.CategoryCode = 'ST2' AND ITM_L.ParentID = LCTE.MyItemID AND ITM.ItemID = ITM_L.ToItemID ) , ItemStructure(MyItemID) AS ( SELECT ItemID AS MyItemID FROM XBOLTADM.TB_ITEM WHERE ItemID = #{strItemID}
UNION ALL SELECT MyItemID FROM ItemMaster ) Select Distinct Row_Number()OVER(ORDER BY TITO.Identifier ) as RNUM , TITO.ItemID AS ItemID , TDF.Name AS FltpName , TF.FileRealName , TDC.Name AS ClassName , TITO.Identifier , TIA.PlainText AS ItemName , XBOLTADM.fn_GetStrItemPath(ITM_STR.MyItemID,#{languageID},TITO.ItemID,'N','') As ItemPath , Convert(nvarchar(10),CONVERT(datetime,TF.LastUpdated),120) AS LastUpdated , TF.DocumentID , TF.Seq , ISNULL(TM.Name,'') + Case When ISNULL(TM.NameEN,'') != '' Then '(' + ISNULL(TM.NameEN,'') + ')' Else '' End As RegUserName , ISNULL(TM2.Name,'') + Case When ISNULL(TM2.NameEN,'') != '' Then '(' + ISNULL(TM2.NameEN,'') + ')' Else '' End As LastUser , TF.DownCNT , TFTP.FilePath+TF.FileName as SysFile , TFTP.FilePath+TF.FileRealName as OrgFile , TFTP.FilePath , TCS.Version , CONVERT(nvarchar(10),CONVERT(datetime,TCS.ValidFrom),120) AS ValidFrom , TL.LanguageCode , ITM_STR.MyItemID AS StrItemID FROM ItemStructure ITM_STR, XBOLTADM.TB_ITEM TI, XBOLTADM.TB_ITEM TITO Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA ON TIA.ItemID = TITO.ItemID and TIA.AttrTypeCode = 'AT00001' And TIA.LanguageID = #{languageID} INNER JOIN XBOLTADM.TB_FILE TF ON TF.DocumentID = TITO.ItemID Left Outer Join XBOLTADM.TB_DICTIONARY TDC ON TDC.TypeCode = TITO.ClassCode And TDC.Category = 'CLS' And TDC.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_DICTIONARY TDF On TDF.TypeCode = TF.FltpCode And TDF.LanguageID = #{languageID}
Left outer join XBOLTADM.TB_MEMBER TM on TF.RegMemberID = TM.MemberID Left outer join XBOLTADM.TB_MEMBER TM2 on TF.LastUser = TM2.MemberID Left Outer Join XBOLTADM.TB_FLTP TFTP ON TFTP.FltpCode = TF.FltpCode Left Outer Join XBOLTADM.TB_CHANGE_SET TCS ON TITO.CurChangeSet = TCS.ChangeSetID Left Outer Join XBOLTADM.TB_LANGUAGE TL On TL.LanguageID = TF.LanguageID
Where ITM_STR.MyItemID = TI.ItemID And TITO.ItemID = TI.ToItemID
And TF.Blocked != 2
AND TITO.ClassCode IN (${classCode})
AND TF.LanguageID = #{selectedLanguageID}
AND TF.FltpCode = #{fltpCode}
AND CONVERT(varchar(10), TF.LastUpdated, 120) BETWEEN #{startLastUpdated} AND #{endLastUpdated}
AND TIA.PlainText Like '%'+#{itemName}+'%'
AND TF.FileRealName Like '%'+#{fileName}+'%'
AND TM.Name Like '%'+#{regUserName}+'%'
Order By TITO.Identifier

SELECT ISNULL(TFP.FilePath,TF.FilePath) as FilePath FROM XBOLTADM.TB_FILE TF
LEFT OUTER JOIN XBOLTADM.TB_FLTP TFP ON TF.FltpCode = TFP.FltpCode
WHERE Seq = #{seq}

