mapper.select:
Select Distinct Row_Number()OVER(ORDER BY TI.Identifier ) as RNUM , TI.ItemID , TI.Identifier , TIA.PlainText AS ItemName , TI.ClassCode , TM2.Name AS LastUser , Convert(nvarchar(20),TF.LastUpdated, 111) AS LastUpdated , TF.DocumentID , TF.Seq , TF.FileRealName , TD.Name As FltpName , TL.LanguageCode , TM.Name As RegUserName , TF.DownCNT , TFTP.FilePath+TF.FileName as SysFile , TFTP.FilePath+TF.FileRealName as OrigFile , TFTP.FilePath From XBOLTADM.TB_FILE TF Left Outer Join XBOLTADM.TB_ITEM TI ON TI.ItemID = TF.DocumentID LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA ON TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = #{languageID} AND TIA.ItemID = TI.ItemID Left outer join XBOLTADM.TB_MEMBER TM on TF.RegMemberID = TM.MemberID Left outer join XBOLTADM.TB_MEMBER TM2 on TF.LastUser = TM2.MemberID Left Outer Join XBOLTADM.TB_DICTIONARY TD On TD.TypeCode = TF.FltpCode And TD.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_LANGUAGE TL On TL.LanguageID = TF.LanguageID Left Outer Join XBOLTADM.TB_FLTP TFTP ON TFTP.FltpCode = TF.FltpCode Where TF.DocumentID IN(${itemIDs})
AND TF.LanguageID = #{selectedLanguageID}
AND TF.FltpCode = #{fltpCode}
AND CONVERT(varchar(10), TF.LastUpdated, 120) BETWEEN #{startLastUpdated} AND #{endLastUpdated}
AND TIA.PlainText Like '%'+#{itemName}+'%'
AND TF.FileRealName Like '%'+#{fileName}+'%'
AND TM.Name Like '%'+#{regUserName}+'%'
And (TF.Blocked = 0 OR TF.Blocked IS NULL)

Select Distinct TFLTP.FltpCode As CODE, TD.Name AS NAME 
From XBOLTADM.TB_FILE TFL
Left Outer Join XBOLTADM.TB_DICTIONARY TD ON TD.TypeCode = TFL.FltpCode And TD.LanguageID = #{languageID}
Left Outer Join XBOLTADM.TB_FLTP TFLTP ON TFLTP.FltpCode = TFL.FltpCode  

  	
		TFLTP.FileOption = #{fileOption}
	  	
  		
		AND TFLTP.DocCategory = #{docCategory}
	  	

Order By Code

SELECT TF.Seq ,TF.ProjectID ,TF.FileName ,TF.FileFormat ,TF.FileRealName ,TF.FileSize ,TF.FileMgt ,TF.RegMemberID ,CONVERT(CHAR(10),CONVERT(datetime,TF.CreationTime),21) as CreationTime ,CONVERT(CHAR(10),CONVERT(datetime,TF.LastUpdated),21) as LastUpdated ,TF.LastUser ,TF.Version ,TF.DownCNT FROM XBOLTADM.TB_FILE TF
Left Outer Join XBOLTADM.TB_CHANGE_SET TCS ON TF.ChangeSetID = TCS.ChangeSetID WHERE TCS.WFInstanceID = #{wfInstanceID}
WHERE TF.DocumentID = #{srID} AND TF.DocCategory = #{DocCategory}
WHERE TF.ProjectID = #{projectID} AND TF.DocCategory = #{DocCategory}
WHERE TF.ProjectID = #{projectID} AND TF.DocCategory = #{DocCategory}

