mapper.insert:
	INSERT INTO XBOLTADM.TB_FILE_LOG /*insertFileLog*/ (
		 FileID, MemberID, TeamID, Time, ClientID				
 		
			,IpAddress
		
 		
			,source
		
		
			,Comment
		
			
			,FileOption
		
	)
	VALUES(
		#{fileID}, #{sessionUserId}, #{sessionTeamId}, getDate(), #{sessionClientId}
 		
			,#{IpAddress}
		
 		
			,#{source}
		
		
			,#{comment}
		
		
			,#{fileOption}
		
	)

mapper.select:
SELECT FLogID, Row_Number() OVER (order by FL.Time DESC) AS RNUM ,FL.FileID ,FL.MemberID ,FL.TeamID ,FL.Time ,FL.Source ,FL.IpAddress ,FL.Comment ,FL.ClientID ,F.FileRealName ,M.Name ,T.Name as TeamName ,D.Name as FileOption
,Case When ISNULL(M.Photo,'blank_photo.png') = 'blank_photo.png' Then #{blankPhotoUrlPath} Else #{photoUrlPath} + ISNULL(M.Photo,'blank_photo.png') END AS Photo
FROM XBOLTADM.TB_FILE_LOG FL LEFT OUTER JOIN XBOLTADM.TB_MEMBER M on FL.MemberID = M.MemberID LEFT OUTER JOIN XBOLTADM.TB_FILE F on FL.FileId= F.Seq LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT T on FL.TeamID= T.TeamID and F.LanguageID = T.LanguageID LEFT OUTER JOIN XBOLTADM.TB_FLTP FLT on F.FltpCode = FLT.FltpCode LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY D on D.TypeCode = FL.FileOption and D.LanguageID = #{languageID} and D.Category ='FILEOPTION' Where FL.FileID = #{seq}

mapper.update:
UPDATE XBOLTADM.TB_FILE SET
	DocumentID = #{documentID},
	LastUpdated = getDate(),
	LastUser = #{sessionUserId}
WHERE Seq = #{seq}

UPDATE XBOLTADM.TB_FLTP SET

    
        TemplateFileID = #{Seq}
    
    
        TemplateFileID = NULL
    

WHERE FltpCode = #{FltpCode}

mapper.select:
select count(TemplateFileID) 
from XBOLTADM.TB_FLTP_ALLOC TFA 
LEFT JOIN  XBOLTADM.TB_FLTP FL ON TFA.FltpCode = FL.FltpCode
where 

	 TFA.DocCategory = #{docCategory}
	TFA.ItemClassCode = #{itemClassCode}
